-- Proyecto DSS 404 - SQL de referencia
-- Contiene las tablas principales y datos creados por php artisan migrate:fresh --seed.
-- Formato SQLite. Para el proyecto Laravel, lo recomendado es usar migraciones y seeders.

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;

DROP TABLE IF EXISTS "usuarios";
CREATE TABLE "usuarios" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "apellido" varchar not null, "email" varchar not null, "password" varchar not null, "telefono" varchar, "calle" varchar, "ciudad" varchar, "estado_dir" varchar, "codigo_postal" varchar, "rol" integer not null default '1', "estado" integer not null default '1', "email_verificado_en" datetime, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime);


DROP TABLE IF EXISTS "categorias";
CREATE TABLE "categorias" ("id" integer primary key autoincrement not null, "nombre_categoria" varchar not null, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime);


DROP TABLE IF EXISTS "productos";
CREATE TABLE "productos" ("id" integer primary key autoincrement not null, "nombre_producto" varchar not null, "marca_id" integer, "categoria_id" integer, "modelo_anio" integer, "precio_lista" numeric not null default '0', "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("categoria_id") references "categorias"("id") on delete set null);


DROP TABLE IF EXISTS "pedidos";
CREATE TABLE "pedidos" ("id" integer primary key autoincrement not null, "usuario_id" integer not null, "estado_pedido" integer not null default '1', "fecha_pedido" date, "fecha_requerida" date, "fecha_envio" date, "tienda_id" integer, "personal_id" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("usuario_id") references "usuarios"("id") on delete cascade);


DROP TABLE IF EXISTS "items_pedido";
CREATE TABLE "items_pedido" ("id" integer primary key autoincrement not null, "pedido_id" integer not null, "item_id" integer not null, "producto_id" integer not null, "cantidad" integer not null default '1', "precio_lista" numeric not null default '0', "descuento" numeric not null default '0', "deleted_at" datetime, foreign key("pedido_id") references "pedidos"("id") on delete cascade, foreign key("producto_id") references "productos"("id") on delete restrict);


DROP TABLE IF EXISTS "Cotizacion";
CREATE TABLE "Cotizacion" ("ID_cotizacion" integer primary key autoincrement not null, "FechaCotizacion" date not null, "Vencimiento" date, "ID_Empleado" integer not null, "IDCliente" integer not null, "ID_Producto" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("ID_Empleado") references "usuarios"("id"), foreign key("IDCliente") references "usuarios"("id"), foreign key("ID_Producto") references "productos"("id"));


COMMIT;
PRAGMA foreign_keys=ON;
